package co.edu.elecciones.service; import co.edu.elecciones.domain.AuditEvent; import co.edu.elecciones.repository.AuditEventRepository; import jakarta.servlet.http.HttpServletRequest; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.stereotype.Service;
@Service public class AuditService { private final AuditEventRepository repo; public AuditService(AuditEventRepository repo){this.repo=repo;} public void log(String action,String entity,Long id,String details, HttpServletRequest req){ AuditEvent e=new AuditEvent(); var auth=SecurityContextHolder.getContext().getAuthentication(); e.username=auth==null?"system":auth.getName(); e.action=action; e.entity=entity; e.entityId=id; e.details=details; e.ip=req==null?null:req.getRemoteAddr(); repo.save(e);} }
